const [item] = items;
const headers = item.json.headers && typeof item.json.headers === 'object' ? item.json.headers : {};
const normalizedHeaders = Object.fromEntries(Object.entries(headers).map(([key, value]) => [String(key).toLowerCase(), value]));
const expectedSecret = $env.N8N_WEBHOOK_SECRET;
const providedSecret = normalizedHeaders['x-n8n-webhook-secret'];
if (!expectedSecret) {
  throw new Error('N8N_WEBHOOK_SECRET is not configured');
}
if (String(providedSecret ?? '') !== String(expectedSecret)) {
  throw new Error('invalid webhook secret');
}
return items;

function createRunId() {
  return `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 12)}`;
}
const [item] = items;
const payload = item.json.body ?? item.json;
if (!payload.documentId || !payload.uploadId || !payload.filePath) {
  throw new Error('ingestion requires documentId, uploadId, and filePath');
}
return [{ json: {
  documentId: String(payload.documentId),
  uploadId: String(payload.uploadId),
  filePath: String(payload.filePath),
  fileName: String(payload.fileName ?? payload.filePath.split('/').pop() ?? 'document.pdf'),
  mimeType: String(payload.mimeType ?? 'application/pdf'),
  requestId: payload.requestId ? String(payload.requestId) : null,
  ingestionRunId: createRunId(),
} }];

function extractText(json) {
  const candidates = [json.extractedText, json.data, json.text, json.content];
  for (const candidate of candidates) {
    if (typeof candidate === 'string' && candidate.trim()) {
      return candidate;
    }
  }
  return '';
}
const [item] = items;
const source = $('Normalize Request').first().json;
const text = extractText(item.json).replace(/\s+/g, ' ').trim();
if (!text) {
  throw new Error('no extracted text returned from PDF extraction');
}
const chunkSize = 1200;
const overlap = 200;
const chunks = [];
let cursor = 0;
let index = 0;
while (cursor < text.length) {
  const end = Math.min(text.length, cursor + chunkSize);
  const content = text.slice(cursor, end).trim();
  if (content.length > 0) {
    chunks.push({
      json: {
        documentId: source.documentId,
        uploadId: source.uploadId,
        fileName: source.fileName,
        mimeType: source.mimeType,
        requestId: source.requestId,
        ingestionRunId: source.ingestionRunId,
        chunkIndex: index,
        content,
        tokenCount: Math.ceil(content.length / 4),
      },
    });
    index += 1;
  }
  if (end === text.length) {
    break;
  }
  cursor = Math.max(end - overlap, cursor + 1);
}
return chunks;

function fnv1aHex(value, salt) {
  let hash = (0x811c9dc5 ^ salt) >>> 0;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, 0x01000193) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}
const embedding = $json.data?.[0]?.embedding ?? $json.embedding;
if (!Array.isArray(embedding) || embedding.length === 0) {
  throw new Error('embedding response did not include a vector');
}
const source = $('Chunk Text').item.json;
const seed = `${source.documentId}:${source.chunkIndex}`;
const hash = [0, 1, 2, 3].map((salt) => fnv1aHex(seed, salt)).join('');
const pointId = `${hash.slice(0, 8)}-${hash.slice(8, 12)}-5${hash.slice(13, 16)}-${(((Number.parseInt(hash.slice(16, 18), 16) & 0x3f) | 0x80).toString(16).padStart(2, '0'))}${hash.slice(18, 20)}-${hash.slice(20, 32)}`;
return {
  pointId,
  documentId: source.documentId,
  uploadId: source.uploadId,
  fileName: source.fileName,
  mimeType: source.mimeType,
  requestId: source.requestId,
  ingestionRunId: source.ingestionRunId,
  chunkIndex: source.chunkIndex,
  content: source.content,
  tokenCount: source.tokenCount,
  vector: embedding,
};

const executionId = String($execution.id ?? '').trim();
if (!executionId) {
  throw new Error('execution id unavailable for ingestion response');
}
const workflowId = $workflow.id == null ? null : String($workflow.id);
return [{ json: {
  executionId,
  workflowId,
  status: 'running',
  message: 'Document ingestion started.',
} }];

const source = $('Normalize Request').first().json;
return [{ json: {
  documentId: source.documentId,
  ingestionRunId: source.ingestionRunId,
} }];

const source = $('Normalize Request').first().json;
const chunks = $('Build Qdrant Point').all().map((item) => {
  const json = item.json;
  const tokenCount = Number(json.tokenCount);
  return {
    chunkIndex: Number(json.chunkIndex),
    content: String(json.content ?? ''),
    tokenCount: Number.isFinite(tokenCount) ? tokenCount : null,
    pointId: String(json.pointId ?? ''),
  };
}).filter((chunk) => Number.isInteger(chunk.chunkIndex) && chunk.content && chunk.pointId).sort((left, right) => left.chunkIndex - right.chunkIndex);
if (chunks.length === 0) {
  throw new Error('completion callback requires at least one chunk');
}
const executionId = String($execution.id ?? '').trim();
return [{ json: {
  documentId: String(source.documentId),
  uploadId: String(source.uploadId),
  externalExecutionId: executionId || null,
  workflowId: $workflow.id == null ? null : String($workflow.id),
  completedAt: new Date().toISOString(),
  embeddingModel: $env.OPENAI_EMBEDDING_MODEL || null,
  chunks,
} }];
